You are implementing Task 26: Geolocation + Proximity Notifications for a loyalty card app.

**Working directory:** C:\Users\User\loyalty-app

**What to do:**

### 1. Install expo-location

```bash
cd apps/mobile && npx expo install expo-location
```

### 2. Create `supabase/migrations/007_postgis.sql`

Note: Use a number that doesn't conflict. Check what migrations exist in `supabase/migrations/` first.

```sql
create extension if not exists postgis;

alter table public.merchants add column if not exists latitude double precision;
alter table public.merchants add column if not exists longitude double precision;
alter table public.merchants add column if not exists geog geography(Point, 4326);

-- Auto-update geography column
create or replace function update_merchant_geog()
returns trigger as $$
begin
  if new.latitude is not null and new.longitude is not null then
    new.geog = st_point(new.longitude, new.latitude)::geography;
  end if;
  return new;
end;
$$ language plpgsql;

create trigger merchant_geog_trigger before insert or update on merchants
  for each row execute function update_merchant_geog();

create index idx_merchants_geog on merchants using gist(geog);
```

### 3. Create `apps/mobile/hooks/useLocation.ts`

```typescript
import { useEffect } from 'react';
import * as Location from 'expo-location';
import { supabase } from '../lib/supabase';
import { useAuthStore } from '../lib/store';

export function useLocation() {
  const session = useAuthStore((s) => s.session);

  useEffect(() => {
    if (!session) return;

    let subscription: Location.LocationSubscription;

    async function start() {
      const { status } = await Location.requestForegroundPermissionsAsync();
      if (status !== 'granted') return;

      subscription = await Location.watchPositionAsync(
        { accuracy: Location.Accuracy.Balanced, distanceInterval: 200 },
        async (location) => {
          await supabase.functions.invoke('proximity-check', {
            body: {
              lat: location.coords.latitude,
              lng: location.coords.longitude,
            },
          });
        }
      );
    }

    start();
    return () => { subscription?.remove(); };
  }, [session]);
}
```

### 4. Create `supabase/functions/proximity-check/index.ts`

```typescript
import { createClient } from 'https://esm.sh/@supabase/supabase-js@2';

const corsHeaders = {
  'Access-Control-Allow-Origin': '*',
  'Access-Control-Allow-Headers': 'authorization, x-client-info, apikey, content-type',
};

Deno.serve(async (req) => {
  if (req.method === 'OPTIONS') return new Response('ok', { headers: corsHeaders });

  try {
    const supabase = createClient(
      Deno.env.get('SUPABASE_URL')!,
      Deno.env.get('SUPABASE_SERVICE_ROLE_KEY')!
    );

    const authHeader = req.headers.get('Authorization');
    if (!authHeader) return new Response(JSON.stringify({ error: 'Unauthorized' }), { status: 401, headers: corsHeaders });

    // Get the authenticated user
    const { data: { user } } = await supabase.auth.getUser(authHeader.replace('Bearer ', ''));
    if (!user) return new Response(JSON.stringify({ error: 'Unauthorized' }), { status: 401, headers: corsHeaders });

    const { lat, lng } = await req.json();
    if (!lat || !lng) return new Response(JSON.stringify({ error: 'Missing lat/lng' }), { status: 400, headers: corsHeaders });

    // Find merchants within 500m
    const { data: nearbyMerchants } = await supabase.rpc('find_nearby_merchants', {
      user_lat: lat,
      user_lng: lng,
      radius_meters: 500,
    });

    const oneDayAgo = new Date(Date.now() - 24 * 60 * 60 * 1000).toISOString();
    let sent = 0;

    for (const merchant of nearbyMerchants ?? []) {
      // Check if customer has a card with this merchant
      const { data: cards } = await supabase
        .from('customer_cards')
        .select('id, loyalty_programs!inner(merchant_id)')
        .eq('customer_id', user.id)
        .eq('loyalty_programs.merchant_id', merchant.id);

      if (!cards || cards.length === 0) continue;

      // Dedup: check if proximity notification sent in last 24h
      const { count } = await supabase
        .from('notifications')
        .select('id', { count: 'exact', head: true })
        .eq('customer_id', user.id)
        .eq('type', 'proximity')
        .gte('sent_at', oneDayAgo);

      if ((count ?? 0) > 0) continue;

      // Get customer push token
      const { data: customer } = await supabase
        .from('customers')
        .select('push_token')
        .eq('id', user.id)
        .single();

      if (!customer?.push_token) continue;

      await fetch('https://exp.host/--/api/v2/push/send', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          to: customer.push_token,
          title: `You're near ${merchant.name}!`,
          body: 'Check your rewards and offers!',
          data: { type: 'proximity', merchant_id: merchant.id },
        }),
      });

      await supabase.from('notifications').insert({
        customer_id: user.id,
        title: `You're near ${merchant.name}!`,
        body: 'Check your rewards and offers!',
        type: 'proximity',
        sent_at: new Date().toISOString(),
      });
      sent++;
    }

    return new Response(JSON.stringify({ sent }), {
      status: 200,
      headers: { ...corsHeaders, 'Content-Type': 'application/json' },
    });
  } catch (err) {
    return new Response(JSON.stringify({ error: (err as Error).message }), { status: 500, headers: corsHeaders });
  }
});
```

We also need a PostGIS function. Add to the same migration file OR create a separate one:

### 5. Add the RPC function to the PostGIS migration

Add to the migration file:
```sql
create or replace function find_nearby_merchants(user_lat double precision, user_lng double precision, radius_meters int)
returns table(id uuid, name text, latitude double precision, longitude double precision, distance double precision) as $$
  select m.id, m.name, m.latitude, m.longitude,
    st_distance(m.geog, st_point(user_lng, user_lat)::geography) as distance
  from merchants m
  where m.geog is not null
    and st_dwithin(m.geog, st_point(user_lng, user_lat)::geography, radius_meters)
  order by distance;
$$ language sql stable;
```

### 6. Add useLocation to root layout

Read `apps/mobile/app/_layout.tsx` and add `useLocation()` call inside the RootLayout component (after `useNotifications()`).

### 7. Commit

```bash
git add .
git commit -m "feat: add geolocation with proximity notifications"
```

**Important:**
- Read existing files before modifying
- Check what migration numbers already exist and use the next available
- Do NOT skip the commit

